        ed_commCd.setValue("");
    }
};

scwin.callbackComm4 = function(rtnList) {
    if (!$c.gus.cfIsNull(rtnList) && rtnList[0] != "N/A") {
        ed_scalCommCd.setValue(rtnList[0]);
